1	type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
2	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
3	type QuoteResult = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const ITEM_BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const premiumForItem = (itemBase: number): number =>
16	  itemBase + Math.ceil(itemBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
17	
18	const quoteFor = (step: QuoteStep): QuoteResult => {
19	  if (step.items.length === 0) return { premium: PROCESSING_FEE };
20	  const itemBase = ITEM_BASE_PREMIUMS[step.items[0].type];
21	  return { premium: premiumForItem(itemBase) };
22	};
23	
24	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
25	  return { results: input.steps.map(quoteFor) };
26	};
