81	  it.todo("dragon-material sword, exact ench 8, damage 1000 G — payout 400 G (50% applies, then deductible)");
82	
83	  // ===== Deductible per damage event =====
84	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
85	
