87	  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
88	  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
89	  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");
90	
91	  // ===== Cap exhaustion =====
92	  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
93	  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
94	  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
95	  it.todo("sword cap 2000 G, two successive 1500 G claims — payouts 1400 G then 600 G; remainingCap 600 then 0");
96	
97	  // ===== Error cases =====
