const premiumFor = (totalBase: number): number =>
  totalBase + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;

const baseFor = (item: { type: string }): number => ITEM_BASE_PREMIUMS[item.type];

const quoteFor = (step: QuoteStep): QuoteResult => ({
  premium: premiumFor(step.items.reduce((sum, item) => sum + baseFor(item), 0)),
});

